// scripts/verify-registry.js
// Pre-build verification script to detect potential dependency confusion

const { execSync } = require('child_process');
const packageJson = require('../package.json');

const PRIVATE_SCOPE = '@company';
const EXPECTED_PRIVATE_REGISTRY = 'https://npm.company.internal';
const PUBLIC_REGISTRY = 'https://registry.npmjs.org';

function getAllDependencies() {
  const deps = {
    ...packageJson.dependencies,
    ...packageJson.devDependencies,
    ...(packageJson.peerDependencies || {}),
    ...(packageJson.optionalDependencies || {})
  };
  return deps;
}

function verifyScopedPackagesNotOnPublicRegistry(deps) {
  const scopedPackages = Object.keys(deps).filter(name => name.startsWith(PRIVATE_SCOPE + '/'));
  const violations = [];

  console.log(`\n🔍 Checking ${scopedPackages.length} scoped packages for dependency confusion...\n`);

  for (const pkg of scopedPackages) {
    try {
      // Attempt to find the package on the public npm registry
      // If it exists there, it's a potential dependency confusion attack
      const result = execSync(
        `npm view ${pkg} --registry ${PUBLIC_REGISTRY} 2>&1`,
        { encoding: 'utf-8', timeout: 10000 }
      );

      // If we get here without error, the package exists on public registry
      violations.push({
        package: pkg,
        issue: 'CRITICAL: Package found on public npm registry - potential dependency confusion!'
      });
    } catch (error) {
      // 404 is expected - the package should NOT exist on public registry
      if (error.status === 1 || error.stderr?.includes('404') || error.stdout?.includes('404')) {
        console.log(`  ✅ ${pkg} - Not found on public registry (safe)`);
      } else {
        console.log(`  ⚠️  ${pkg} - Could not verify (network issue?): ${error.message}`);
      }
    }
  }

  return violations;
}

function verifyNpmrcConfiguration() {
  const fs = require('fs');
  const path = require('path');
  const issues = [];

  const npmrcPath = path.join(__dirname, '..', '.npmrc');

  if (!fs.existsSync(npmrcPath)) {
    issues.push('CRITICAL: .npmrc file is missing! Scoped packages may resolve from public registry.');
    return issues;
  }

  const npmrcContent = fs.readFileSync(npmrcPath, 'utf-8');

  // Check that the scope is pinned to private registry
  const scopeRegistryPattern = new RegExp(
    `${PRIVATE_SCOPE.replace('/', '\\/')}:registry\\s*=\\s*${EXPECTED_PRIVATE_REGISTRY.replace(/\//g, '\\/')}`
  );

  if (!scopeRegistryPattern.test(npmrcContent)) {
    issues.push(
      `CRITICAL: .npmrc does not pin ${PRIVATE_SCOPE} scope to ${EXPECTED_PRIVATE_REGISTRY}`
    );
  } else {
    console.log(`  ✅ .npmrc correctly pins ${PRIVATE_SCOPE} to private registry`);
  }

  // Check that always-auth is enabled for private registry
  if (!npmrcContent.includes('always-auth=true')) {
    issues.push('WARNING: always-auth is not enabled for the private scope');
  } else {
    console.log('  ✅ always-auth is enabled for private scope');
  }

  // Check strict-ssl
  if (npmrcContent.includes('strict-ssl=false')) {
    issues.push('WARNING: strict-ssl is disabled - this weakens security');
  } else {
    console.log('  ✅ strict-ssl is not disabled');
  }

  return issues;
}

function verifyPackageLockIntegrity() {
  const fs = require('fs');
  const path = require('path');
  const issues = [];

  const lockPath = path.join(__dirname, '..', 'package-lock.json');

  if (!fs.existsSync(lockPath)) {
    issues.push('WARNING: package-lock.json not found. Run npm install to generate it.');
    return issues;
  }

  const lockContent = JSON.parse(fs.readFileSync(lockPath, 'utf-8'));
  const packages = lockContent.packages || {};

  for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
    const pkgName = pkgPath.replace('node_modules/', '');

    if (pkgName.startsWith(PRIVATE_SCOPE + '/')) {
      // Verify the resolved URL points to private registry
      if (pkgInfo.resolved && !pkgInfo.resolved.startsWith(EXPECTED_PRIVATE_REGISTRY)) {
        issues.push(
          `CRITICAL: ${pkgName} resolves to ${pkgInfo.resolved} instead of private registry!`
        );
      } else if (pkgInfo.resolved) {
        console.log(`  ✅ ${pkgName} resolves to private registry in lockfile`);
      }
    }
  }

  return issues;
}

// Main execution
console.log('='.repeat(70));
console.log('  Dependency Confusion Security Audit');
console.log('='.repeat(70));

const allDeps = getAllDependencies();
let allIssues = [];

// Step 1: Verify .npmrc configuration
console.log('\n📋 Step 1: Verifying .npmrc configuration...');
allIssues = allIssues.concat(verifyNpmrcConfiguration());

// Step 2: Verify package-lock.json integrity
console.log('\n📋 Step 2: Verifying package-lock.json registry resolution...');
allIssues = allIssues.concat(verifyPackageLockIntegrity());

// Step 3: Check if scoped packages exist on public registry
console.log('\n📋 Step 3: Checking public registry for scoped package name collisions...');
const confusionViolations = verifyScopedPackagesNotOnPublicRegistry(allDeps);
allIssues = allIssues.concat(confusionViolations.map(v => `${v.issue} (${v.package})`));

// Report
console.log('\n' + '='.repeat(70));

const criticalIssues = allIssues.filter(i => i.startsWith('CRITICAL'));
const warnings = allIssues.filter(i => i.startsWith('WARNING'));

if (criticalIssues.length > 0) {
  console.log(`\n🚨 ${criticalIssues.length} CRITICAL issue(s) found:\n`);
  criticalIssues.forEach(issue => console.log(`  ❌ ${issue}`));
}

if (warnings.length > 0) {
  console.log(`\n⚠️  ${warnings.length} warning(s) found:\n`);
  warnings.forEach(issue => console.log(`  ⚠️  ${issue}`));
}

if (allIssues.length === 0) {
  console.log('\n✅ All dependency confusion checks passed!\n');
  process.exit(0);
} else if (criticalIssues.length > 0) {
  console.log('\n❌ Build blocked due to critical security issues.\n');
  process.exit(1);
} else {
  console.log('\n⚠️  Build proceeding with warnings. Please review.\n');
  process.exit(0);
}